INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (100, 1, 0.0, "2024/10/31 12:00:00", 130011, "2030/01/01 14:59:59", "ヤマト", 2.1, -416.5, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 3001, 3001100, 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (101, 4, 0.0, "2024/10/31 12:00:00", 130011, "2030/01/01 14:59:59", "ヤマト", 5.68, -416.5, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 3001, 3001101, 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (102, 1, 0.0, "2024/10/31 12:00:00", 130011, "2030/01/01 14:59:59", "ヤマト", 0.0, -416.5, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 3001, 3001102, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (100, 1, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 0.0, -416.5, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 3002, 3002100, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (101, 1, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 0.0, -416.5, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 3002, 3002101, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (102, 5, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 8.53, -416.5, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 3002, 3002102, 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (103, 7, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 5.67, -416.5, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 3002, 3002103, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (104, 1, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 0.0, -416.5, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 3002, 3002104, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (300, 3, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 0.0, -416.5, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 3004, 3002300, 3);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (301, 7, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 0.0, -416.5, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 3005, 3002400, 7);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (200, 2, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 4.4, -416.5, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 3003, 3003200, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (201, 7, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 0.0, -416.5, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 3003, 3003201, 7);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (202, 1, 0.0, "2024/10/31 12:00:00", 130211, "2030/01/01 14:59:59", "フブキ", 5.6, -416.5, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 3003, 3003202, 2);
